from typing import List

class SummaryRanges:

    def __init__(self):
        self.intervals = []

    def addNum(self, value: int) -> None:
        if not self.intervals or self.intervals[-1][1] + 1 < value:
            self.intervals.append([value, value])
        else:
            self.intervals[-1][1] = max(self.intervals[-1][1], value)

    def getIntervals(self) -> List[List[int]]:
        self.intervals = [list(interval) for interval in set(tuple(interval) for interval in self.intervals)]
        self.intervals.sort(key=lambda x: x[0])
        result = []
        for interval in self.intervals:
            if not result or result[-1][1] + 1 < interval[0]:
                result.append(interval)
            else:
                result[-1][1] = max(result[-1][1], interval[1])
        return result
```

